queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?currency_exchange_service a :Currency_Exchange_Service .
    ?currency_exchange_service p:name ?name .
    ?currency_exchange_service p:Location_Within_Terminal ?location_within_terminal_f .
    FILTER(STR(?location_within_terminal_f) = "Near Gate 10")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?atm_machine a :ATM_Machine .
    ?atm_machine p:name ?name .
    ?atm_machine p:Location_Within_Terminal ?location_within_terminal_f .
    FILTER(STR(?location_within_terminal_f) = "Near Gate 10")
    BIND(?name AS ?o0)
  }
}

